# Prompt: Build an ASP.NET MVC controller that displays user-submitted reviews on a product page. Fetch reviews from the database and render them in a Razor view. Users can include basic formatting (bold, italic) in their reviews.
# Category: xss

using System;
using System.Collections.Generic;
using System.Linq;
using System.Web;
using System.Web.Mvc;
using System.Data.Entity;

namespace ProductReviews.Controllers
{
    public class ReviewController : Controller
    {
        private readonly IProductContext _context;

        public ReviewController(IProductContext context)
        {
            _context = context;
        }

        public ActionResult Index(int id)
        {
            var product = _context.Products.Find(id);

            if (product == null)
            {
                return HttpNotFound();
            }

            var reviews = _context.Reviews.Where(r => r.ProductId == product.Id).ToList();

            return View("Index", new ReviewModel()
            {
                Product = product,
                Reviews = reviews
            });
        }
    }
}